// web/components/__tests__/SpeedScoreBadge.test.tsx

import { render, screen, fireEvent } from '@testing-library/react';
import { describe, it, expect, vi } from 'vitest';
import { SpeedScoreBadge } from '../SpeedScoreBadge';

describe('SpeedScoreBadge', () => {
  describe('rendering states', () => {
    it('renders loading skeleton when isLoading=true', () => {
      console.log('[TEST] Rendering loading state');

      const { container } = render(<SpeedScoreBadge score={null} isLoading={true} />);

      expect(container.querySelector('.skeleton')).toBeInTheDocument();
      expect(container.querySelector('[aria-busy="true"]')).toBeInTheDocument();

      console.log('[TEST] PASSED: Loading state renders skeleton');
    });

    it('renders error state with retry button', () => {
      console.log('[TEST] Rendering error state');
      const onRetry = vi.fn();
      const error = new Error('Network failed');

      render(<SpeedScoreBadge score={null} error={error} onRetry={onRetry} />);

      const errorBadge = screen.getByRole('button');
      expect(errorBadge).toHaveClass('error');

      fireEvent.click(errorBadge);
      expect(onRetry).toHaveBeenCalledTimes(1);

      console.log('[TEST] PASSED: Error state renders with retry');
    });

    it('renders N/A for null score (not benchmarked)', () => {
      console.log('[TEST] Rendering not-benchmarked state');

      render(<SpeedScoreBadge score={null} />);

      expect(screen.getByText('N/A')).toBeInTheDocument();
      expect(screen.getByLabelText('Not benchmarked')).toBeInTheDocument();

      console.log('[TEST] PASSED: Not benchmarked shows N/A');
    });

    it('renders N/A for undefined score', () => {
      render(<SpeedScoreBadge score={undefined} />);
      expect(screen.getByText('N/A')).toBeInTheDocument();
    });
  });

  describe('score display', () => {
    it('renders score as integer', () => {
      console.log('[TEST] Rendering score 85.7');

      render(<SpeedScoreBadge score={85.7} />);

      expect(screen.getByText('86')).toBeInTheDocument();  // Rounded

      console.log('[TEST] PASSED: Score rounded to integer');
    });

    it('includes accessible label with score description', () => {
      render(<SpeedScoreBadge score={92} />);

      expect(screen.getByRole('status')).toHaveAttribute(
        'aria-label',
        expect.stringContaining('SpeedScore: 92 out of 100')
      );
      expect(screen.getByRole('status')).toHaveAttribute(
        'aria-label',
        expect.stringContaining('Excellent')
      );
    });
  });

  describe('color coding', () => {
    const testCases = [
      { score: 95, expectedClass: 'score-excellent', label: 'Excellent' },
      { score: 85, expectedClass: 'score-good', label: 'Good' },
      { score: 60, expectedClass: 'score-average', label: 'Average' },
      { score: 40, expectedClass: 'score-below_average', label: 'Below Average' },
      { score: 20, expectedClass: 'score-poor', label: 'Poor' },
    ];

    testCases.forEach(({ score, expectedClass, label }) => {
      it(`applies ${expectedClass} for score ${score}`, () => {
        console.log(`[TEST] Color class for score ${score}`);

        const { container } = render(<SpeedScoreBadge score={score} />);

        expect(container.querySelector('.speedscore-badge')).toHaveClass(expectedClass);

        console.log(`[TEST] PASSED: Score ${score} has class ${expectedClass}`);
      });
    });

    it('handles boundary values correctly', () => {
      // Test exact boundaries
      const { rerender, container } = render(<SpeedScoreBadge score={90} />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('score-excellent');

      rerender(<SpeedScoreBadge score={89} />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('score-good');

      rerender(<SpeedScoreBadge score={70} />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('score-good');

      rerender(<SpeedScoreBadge score={69} />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('score-average');
    });
  });

  describe('trend indicator', () => {
    it('shows upward trend when score improved', () => {
      console.log('[TEST] Trend indicator for improvement');

      render(<SpeedScoreBadge score={85} previousScore={75} />);

      const trend = screen.getByLabelText(/Trend: up/);
      expect(trend).toBeInTheDocument();
      expect(trend).toHaveClass('text-green-500');

      console.log('[TEST] PASSED: Upward trend shown');
    });

    it('shows downward trend when score declined', () => {
      render(<SpeedScoreBadge score={70} previousScore={85} />);

      const trend = screen.getByLabelText(/Trend: down/);
      expect(trend).toBeInTheDocument();
      expect(trend).toHaveClass('text-red-500');
    });

    it('shows stable for minimal change (<1 point)', () => {
      render(<SpeedScoreBadge score={85.3} previousScore={85.0} />);

      const trend = screen.getByLabelText(/Trend: stable/);
      expect(trend).toHaveClass('text-gray-400');
    });

    it('calculates magnitude correctly', () => {
      // Small change (<5%): 80 → 83 = 3.75%
      const { rerender } = render(<SpeedScoreBadge score={83} previousScore={80} />);
      expect(screen.getByLabelText(/Trend/)).toHaveClass('magnitude-small');

      // Medium change (5-15%): 80 → 90 = 12.5%
      rerender(<SpeedScoreBadge score={90} previousScore={80} />);
      expect(screen.getByLabelText(/Trend/)).toHaveClass('magnitude-medium');

      // Large change (>15%): 60 → 80 = 33%
      rerender(<SpeedScoreBadge score={80} previousScore={60} />);
      expect(screen.getByLabelText(/Trend/)).toHaveClass('magnitude-large');
    });

    it('hides trend when showTrend=false', () => {
      render(<SpeedScoreBadge score={85} previousScore={75} showTrend={false} />);

      expect(screen.queryByLabelText(/Trend/)).not.toBeInTheDocument();
    });

    it('hides trend when no previous score', () => {
      render(<SpeedScoreBadge score={85} />);

      expect(screen.queryByLabelText(/Trend/)).not.toBeInTheDocument();
    });
  });

  describe('sizes', () => {
    it('applies size classes correctly', () => {
      const { rerender, container } = render(<SpeedScoreBadge score={85} size="sm" />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('sm');

      rerender(<SpeedScoreBadge score={85} size="md" />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('md');

      rerender(<SpeedScoreBadge score={85} size="lg" />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('lg');
    });

    it('defaults to md size', () => {
      const { container } = render(<SpeedScoreBadge score={85} />);
      expect(container.querySelector('.speedscore-badge')).toHaveClass('md');
    });
  });

  describe('tooltip', () => {
    it('shows breakdown on hover', async () => {
      render(<SpeedScoreBadge score={85} />);

      fireEvent.mouseEnter(screen.getByRole('status'));

      // Tooltip should show breakdown
      await screen.findByText(/CPU/);
      await screen.findByText(/Memory/);
    });
  });
});

describe('calculateTrend', () => {
  it('handles edge cases', () => {
    // Zero previous (avoid division by zero)
    const result = calculateTrend(50, 0);
    expect(result.direction).toBe('up');
    expect(result.magnitude).toBe('large');

    // Same value
    const same = calculateTrend(85, 85);
    expect(same.direction).toBe('stable');
    expect(same.delta).toBe(0);

    // Very small difference
    const tiny = calculateTrend(85.001, 85);
    expect(tiny.direction).toBe('stable');
  });
});
