### Score Calculation
\`\`\`rust
impl NetworkResult {
    /// Calculate normalized network score (0-100)
    pub fn calculate_score(&self) -> f64 {
        // Reference points calibrated for 2024-2026 hardware/networks
        let upload_score = normalize(self.upload_mbps, 10.0, 1000.0);     // 10 Mbps = 0, 1 Gbps = 100
        let download_score = normalize(self.download_mbps, 10.0, 1000.0);
        let latency_score = normalize(1000.0 / self.latency_ms, 1.0, 100.0);  // Lower latency = higher score

        // Weighted combination
        // Download slightly more important (artifacts are typically larger than source)
        let score = upload_score * 0.35 + 
                    download_score * 0.40 + 
                    latency_score * 0.25;

        score.clamp(0.0, 100.0)
    }
}

fn normalize(value: f64, low: f64, high: f64) -> f64 {
    ((value - low) / (high - low) * 100.0).clamp(0.0, 100.0)
}
